package br.com.portfolio.ecommerce.identity.infrastructure.security;
import com.auth0.jwt.JWT; import com.auth0.jwt.algorithms.Algorithm; import org.springframework.beans.factory.annotation.Value; import org.springframework.stereotype.Service; import java.time.*; import java.util.*;
@Service public class JwtService { private final String secret; private final String issuer; private final long minutes; public JwtService(@Value("${app.jwt.secret}") String secret,@Value("${app.jwt.issuer}") String issuer,@Value("${app.jwt.expiration-minutes}") long minutes){this.secret=secret;this.issuer=issuer;this.minutes=minutes;} public String generate(String subject,String role){ return JWT.create().withIssuer(issuer).withSubject(subject).withClaim("role",role).withExpiresAt(Date.from(Instant.now().plus(Duration.ofMinutes(minutes)))).sign(Algorithm.HMAC256(secret)); } }
